// IMAP 메일에서 필드 추출. message_id 없으면 대체키 생성. [Each Item]
const j = $json;
const subject = (j.subject || '').toString();
const fr = j.from;
const from = (fr && (fr.text || (fr.value && fr.value[0] && fr.value[0].address))) || (typeof fr==='string'?fr:'') || '';
const received_at = j.date || null;
const body = (j.text || j.textAsHtml || (typeof j.html==='string'?j.html:'') || '').toString().replace(/\s+/g,' ').slice(0,3000);
let message_id = j.messageId || (j.headers && (j.headers['message-id']||j.headers['Message-ID'])) || '';
if (!message_id) message_id = 'h:' + subject + '|' + from + '|' + (received_at||'');
return { json: { message_id, subject, from, received_at, body } };

// 분류 요청 본문 구성 (gemma, json_schema). reason/evidence를 먼저 생성해 근거 기반 판단(환각 방지). [Each Item]
const p = $json;
const sys = `너는 채용 이메일을 분류한다. 반드시 본문의 실제 문장에 근거해서만 판단하고, 없는 내용을 지어내지 마라.
[분류 순서 — 반드시 이 순서로 판단]
1) 먼저 '거절/탈락' 신호를 찾아라. 한국 채용 거절 메일은 '불합격'이라는 단어를 거의 쓰지 않고 완곡하게 표현한다. 다음 표현이 있으면 무조건 reject:
   "좋은 소식을 전하지/들려드리지 못하게 되었습니다", "모시지 못하게 되었습니다", "함께하지 못하게 되었습니다", "함께하지 못해", "안타깝게도", "아쉽게도", "다음 기회에", "합격하지 못", "부합하지 않아", "선발되지 못".
2) 거절 신호가 없을 때만 합격/진행을 고려한다. '합격', '통과', '축하'가 본문에 명시적으로 있어야 document_pass 또는 final_pass다. 이런 단어가 없으면 절대 document_pass/final_pass로 분류하지 마라.
3) 면접·코딩테스트·과제 등 다음 전형 진행 안내면 interview.
4) 접수/지원완료 확인만 있고 결과가 없으면 applied.
5) 채용과 무관(광고·뉴스레터·시스템/보안 알림)이면 other.
[status] applied, document_pass, interview, final_pass, reject, other 중 하나만.
company=회사명(제목 [] 안이나 발신 도메인에서). 모르면 "". summary=본문에 실제로 있는 내용 한 줄(지어내지 말 것).`;
const schema = { type:"object", additionalProperties:false, properties:{
  reason:{type:"string"},
  evidence:{type:"string"},
  status:{type:"string", enum:["applied","document_pass","interview","final_pass","reject","other"]},
  company:{type:"string"}, summary:{type:"string"} }, required:["reason","evidence","status","company","summary"] };
const body = { model: $('설정 (Config)').first().json.classModel,
  messages:[{role:"system",content:sys},{role:"user",content:`제목: ${p.subject}\n발신: ${p.from}\n본문: ${p.body}`}],
  temperature:0.1, max_tokens:400, tools:[],
  response_format:{type:"json_schema", json_schema:{name:"cls", schema}} };
return { json: { body } };

// 분류결과 → INSERT SQL. other는 최소저장(개인정보 보호). ON CONFLICT로 중복방지. [Each Item]
const m = $('준비').item.json;
let content=''; try { content = $json.choices[0].message.content; } catch(e){}
let cls={}; try { cls = JSON.parse(content); } catch(e){}
const status = ['applied','document_pass','interview','final_pass','reject','other'].includes(cls.status) ? cls.status : 'other';
const esc = (v)=> v==null ? 'NULL' : `'${String(v).replace(/'/g,"''")}'`;
const recv = m.received_at ? `${esc(m.received_at)}::timestamptz` : 'NULL';
let sql;
if (status==='other') {
  sql = `INSERT INTO applications(message_id,status,received_at) VALUES(${esc(m.message_id)},'other',${recv}) ON CONFLICT(message_id) DO NOTHING RETURNING message_id,status,company,summary;`;
} else {
  sql = `INSERT INTO applications(message_id,company,status,email_subject,email_from,summary,received_at) VALUES(${esc(m.message_id)},${esc(cls.company||'')},'${status}',${esc(m.subject)},${esc(m.from)},${esc(cls.summary||'')},${recv}) ON CONFLICT(message_id) DO NOTHING RETURNING message_id,status,company,summary;`;
}
return { json: { sql } };

// 새로 삽입된 결과만 → 디스코드 payload(+메일 링크) + notified UPDATE. [Each Item]
const r = $json;
if (!r || !r.message_id || r.status == null) return [];  // 빈 행(중복 ON CONFLICT DO NOTHING) 방어
const icon = ({document_pass:'📄',interview:'📅',final_pass:'🎉',reject:'😢'})[r.status] || '📩';
const label = ({document_pass:'서류 합격',interview:'면접·전형 안내',final_pass:'최종 합격',reject:'불합격'})[r.status] || r.status;
const idx = $('설정 (Config)').first().json.gmailUserIndex || '0';
const mid = r.message_id || '';
let link = '';
if (mid && !mid.startsWith('h:')) link = `https://mail.google.com/mail/u/${idx}/#search/rfc822msgid:` + encodeURIComponent(mid.replace(/[<>]/g,''));
const content = `${icon} **[${r.company||'회사미상'}]** ${label}\n> ${(r.summary||'').slice(0,200)}` + (link ? `\n📧 메일 열기: ${link}` : '');
const esc = (v)=> String(v).replace(/'/g,"''");
return { json: {
  webhook: $('설정 (Config)').first().json.discordWebhookUrl,
  discordBody: JSON.stringify({ content }),
  notifiedSql: `UPDATE applications SET notified_at=now() WHERE message_id='${esc(r.message_id)}';`
} };
